import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by encoding it before outputting
        PrintWriter out = new PrintWriter(System.out);
        HTMLEntityCodec codec = new HTMLEntityCodec();

        out.println("<html>");
        out.println("<body>");
        out.println("<p>User Input: " + codec.encodeForHTML(userInput) + "</p>"); // Fixed to encode user input
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
